import{_ as p,C as E,o as s,c as d,a5 as l,b as e,w as n,a as t,E as A,a4 as r}from"./chunks/framework.gGRxziV4.js";const q=JSON.parse('{"title":"04 - Commands 系统：预设好的对话模板","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/04-Commands系统.md","filePath":"08-ECC教程/04-Commands系统.md","lastUpdated":null}'),i={name:"08-ECC教程/04-Commands系统.md"};function c(f,a,u,m,B,C){const o=E("Mermaid");return s(),d("div",null,[a[6]||(a[6]=l(`<h1 id="_04-commands-系统-预设好的对话模板" tabindex="-1">04 - Commands 系统：预设好的对话模板 <a class="header-anchor" href="#_04-commands-系统-预设好的对话模板" aria-label="Permalink to &quot;04 - Commands 系统：预设好的对话模板&quot;">​</a></h1><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Commands 就是给 AI 准备的&quot;快捷键&quot;——你不用每次打一大段话解释工作方式，一个命令搞定。</p><hr><h2 id="真实痛点-你在花大量时间-教-ai-怎么干活" tabindex="-1">真实痛点：你在花大量时间&quot;教 AI 怎么干活&quot; <a class="header-anchor" href="#真实痛点-你在花大量时间-教-ai-怎么干活" aria-label="Permalink to &quot;真实痛点：你在花大量时间&quot;教 AI 怎么干活&quot;&quot;">​</a></h2><p>先来看一个你可能很熟悉的场景：</p><blockquote><p>你：帮我写个用户登录功能。 AI：好的！[直接开始写代码，从数据库到 API 到前端一步到位] 你：等等，你还没规划呢。 AI：好的，那我先规划。 你：规划完别直接写，先给我看看。 AI：好的。 你：规划的时候要考虑测试。 AI：好的。 你：还有安全。 AI：好的。 ……又来回了 8 轮</p></blockquote><p>发现问题了吗？你花了大量时间在<strong>重复描述工作方式</strong>上，而不是在解决实际问题。</p><p>为什么会这样？因为每次对话，AI 都像一个&quot;刚入职的实习生&quot;——TA 能力很强，但不知道你希望 TA 怎么工作。你得一遍遍告诉 TA：&quot;先规划再动手&quot;、&quot;写完要测试&quot;、&quot;改完要审查&quot;。</p><p><strong>这些工作方式，其实每次都一样。</strong> 那为什么不把它&quot;固化&quot;下来？</p><hr><h2 id="commands-的核心思想-预设对话模板" tabindex="-1">Commands 的核心思想：预设对话模板 <a class="header-anchor" href="#commands-的核心思想-预设对话模板" aria-label="Permalink to &quot;Commands 的核心思想：预设对话模板&quot;">​</a></h2><p>一个 Command 本质上就是一份<strong>提前写好的&quot;工作说明书&quot;</strong>。</p><p>你输入 <code>/plan</code>，系统把 plan 的说明书&quot;喂&quot;给 AI，AI 就按照这个说明书来工作——先分析需求、再拆步骤、识别风险、等你确认。</p><p>打个比方：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>没有 Commands 时：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  你每次去理发 → 从头解释一遍：&quot;剪短 3 厘米，两边推平，上面打薄&quot;</span></span>
<span class="line"><span>  理发师：好的，剪短 3 厘米是吧？两边推平？上面呢？</span></span>
<span class="line"><span>  你：打薄！</span></span>
<span class="line"><span>  理发师：打薄多少？</span></span>
<span class="line"><span>  你：……（又来一轮）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有了 Commands 时：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  你：老样子 ✂️</span></span>
<span class="line"><span>  理发师：好嘞！[立刻动手，因为上次已经记住了你的要求]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Commands 就是那个&quot;老样子&quot;——<strong>把重复的沟通成本降为零</strong>。</p>`,17)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-47",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20INPUT%5B%22%F0%9F%8E%A4%20%E4%BD%A0%E8%BE%93%E5%85%A5%EF%BC%9A%2Fplan%20%E5%81%9A%E7%94%A8%E6%88%B7%E7%99%BB%E5%BD%95%E5%8A%9F%E8%83%BD%22%5D%0A%20%20%20%20PARSER%5B%22%F0%9F%94%8D%20%E5%91%BD%E4%BB%A4%E8%A7%A3%E6%9E%90%5Cn%E8%AF%86%E5%88%AB%E5%88%B0%20%2Fplan%22%5D%0A%20%20%20%20CONFIG%5B%22%F0%9F%93%84%20%E5%8A%A0%E8%BD%BD%20plan.md%5Cn%E5%B7%A5%E4%BD%9C%E8%AF%B4%E6%98%8E%E4%B9%A6%EF%BC%9A%5Cn1.%20%E5%88%86%E6%9E%90%E9%9C%80%E6%B1%82%5Cn2.%20%E8%AF%86%E5%88%AB%E9%A3%8E%E9%99%A9%5Cn3.%20%E6%8B%86%E6%88%90%E6%AD%A5%E9%AA%A4%5Cn4.%20%E7%AD%89%E7%94%A8%E6%88%B7%E7%A1%AE%E8%AE%A4%22%5D%0A%20%20%20%20EXEC%5B%22%F0%9F%A4%96%20AI%20%E6%8C%89%E8%AF%B4%E6%98%8E%E4%B9%A6%E5%B7%A5%E4%BD%9C%5Cn%E4%B8%8D%E4%BC%9A%E4%B9%B1%E6%9D%A5%EF%BC%8C%E4%B8%8D%E4%BC%9A%E5%81%8F%E7%A6%BB%E8%BD%A8%E9%81%93%22%5D%0A%0A%20%20%20%20INPUT%20--%3E%20PARSER%20--%3E%20CONFIG%20--%3E%20EXEC%0A%0A%20%20%20%20style%20INPUT%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20PARSER%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20CONFIG%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20EXEC%20fill%3A%231a237e%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[t(" Loading... ",-1)])]),_:1})),a[7]||(a[7]=l('<hr><h2 id="为什么是这些-commands-来自真实开发流程的痛点" tabindex="-1">为什么是这些 Commands？来自真实开发流程的痛点 <a class="header-anchor" href="#为什么是这些-commands-来自真实开发流程的痛点" aria-label="Permalink to &quot;为什么是这些 Commands？来自真实开发流程的痛点&quot;">​</a></h2><p>Commands 不是随便设计的。每一个都对应开发流程中的一个<strong>真实痛点</strong>：</p><h3 id="_1-plan-——-因为-不规划直接写代码-是-ai-编程最大的坑" tabindex="-1">1. <code>/plan</code> —— 因为&quot;不规划直接写代码&quot;是 AI 编程最大的坑 <a class="header-anchor" href="#_1-plan-——-因为-不规划直接写代码-是-ai-编程最大的坑" aria-label="Permalink to &quot;1. `/plan` —— 因为&quot;不规划直接写代码&quot;是 AI 编程最大的坑&quot;">​</a></h3><p>你有没有遇到过这种情况：让 AI 写一个功能，TA 哗哗写了一堆代码，你一看，方向就错了？</p><p>AI 写代码太快了，快到你来不及阻止。TA 可能在你还在想需求的时候，就已经把数据库表设计好了——而且设计错了。</p><p><strong><code>/plan</code> 解决的就是这个问题：先想后做。</strong> 它强制 AI 进入&quot;规划模式&quot;——只分析、只拆步骤，不写代码。等你确认了，才动手。</p>',7)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-67",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20N%5B%22%E6%B2%A1%E6%9C%89%20%2Fplan%22%5D%20--%3E%20D%5B%22%E7%9B%B4%E6%8E%A5%E5%86%99%E4%BB%A3%E7%A0%81%22%5D%20--%3E%20W%5B%22%E6%96%B9%E5%90%91%E9%94%99%E4%BA%86%22%5D%20--%3E%20R%5B%22%E6%8E%A8%E5%80%92%E9%87%8D%E6%9D%A5%22%5D%0A%20%20%20%20Y%5B%22%E6%9C%89%20%2Fplan%22%5D%20--%3E%20P%5B%22%E5%85%88%E8%A7%84%E5%88%92%22%5D%20--%3E%20C%5B%22%E4%BD%A0%E7%A1%AE%E8%AE%A4%22%5D%20--%3E%20G%5B%22%E6%96%B9%E5%90%91%E6%AD%A3%E7%A1%AE%22%5D%0A%0A%20%20%20%20style%20N%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20D%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20W%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20R%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20Y%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20P%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20C%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20G%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[1]||(a[1]=[t(" Loading... ",-1)])]),_:1})),a[8]||(a[8]=l('<p><strong>实际效果：</strong> 输入 <code>/plan 做用户登录功能，邮箱+手机号，JWT认证</code>，AI 会输出一个完整的实施计划：分几个阶段、每个阶段做什么、有哪些风险点。你看完觉得 OK，回复&quot;确认&quot;，TA 才开始写代码。</p><hr><h3 id="_2-tdd-——-因为-先写代码再补测试-永远补不完" tabindex="-1">2. <code>/tdd</code> —— 因为&quot;先写代码再补测试&quot;永远补不完 <a class="header-anchor" href="#_2-tdd-——-因为-先写代码再补测试-永远补不完" aria-label="Permalink to &quot;2. `/tdd` —— 因为&quot;先写代码再补测试&quot;永远补不完&quot;">​</a></h3><p>说句实话：没有一个程序员喜欢补测试。</p><p>写代码的时候热血沸腾，写完之后回头补测试？&quot;算了，下次吧。&quot;然后就没有下次了。</p><p><strong>TDD（测试驱动开发）的核心理念是反过来：先写测试，再写代码。</strong> 听起来很反直觉，但其实特别合理——</p><p>打个比方：你要盖房子。传统方式是先盖楼，盖完了再检查质量。TDD 是先画好&quot;合格标准&quot;（测试），然后按照标准来盖。</p>',7)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-87",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20RED%5B%22%F0%9F%94%B4%20RED%5Cn%E5%86%99%E4%B8%80%E4%B8%AA%E6%B5%8B%E8%AF%95%5Cn%E8%BF%90%E8%A1%8C%20%E2%86%92%20%E5%A4%B1%E8%B4%A5%5Cn%EF%BC%88%E5%9B%A0%E4%B8%BA%E4%BB%A3%E7%A0%81%E8%BF%98%E4%B8%8D%E5%AD%98%E5%9C%A8%EF%BC%89%22%5D%0A%20%20%20%20GREEN%5B%22%F0%9F%9F%A2%20GREEN%5Cn%E5%86%99%E6%9C%80%E5%B0%91%E7%9A%84%E4%BB%A3%E7%A0%81%5Cn%E8%AE%A9%E6%B5%8B%E8%AF%95%E9%80%9A%E8%BF%87%22%5D%0A%20%20%20%20REFACTOR%5B%22%F0%9F%94%B5%20REFACTOR%5Cn%E4%BB%A3%E7%A0%81%E8%83%BD%E8%B7%91%E4%BA%86%5Cn%E7%8E%B0%E5%9C%A8%E8%AE%A9%E5%AE%83%E6%9B%B4%E6%BC%82%E4%BA%AE%5Cn%E4%BF%9D%E6%8C%81%E6%B5%8B%E8%AF%95%E7%BB%BF%20%E2%9C%85%22%5D%0A%0A%20%20%20%20RED%20--%3E%20GREEN%20--%3E%20REFACTOR%20--%3E%20RED%0A%0A%20%20%20%20style%20RED%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20GREEN%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20REFACTOR%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[2]||(a[2]=[t(" Loading... ",-1)])]),_:1})),a[9]||(a[9]=l('<p><strong><code>/tdd</code> 的价值不在于&quot;多写了测试&quot;，而在于&quot;你的代码从第一天就有质量保障&quot;。</strong></p><hr><h3 id="_3-code-review-——-因为-ai-写的代码需要第二双眼睛" tabindex="-1">3. <code>/code-review</code> —— 因为 AI 写的代码需要第二双眼睛 <a class="header-anchor" href="#_3-code-review-——-因为-ai-写的代码需要第二双眼睛" aria-label="Permalink to &quot;3. `/code-review` —— 因为 AI 写的代码需要第二双眼睛&quot;">​</a></h3><p>AI 写代码很快，但&quot;快&quot;不等于&quot;好&quot;。</p><p>AI 可能写出这样的代码：功能正确，但没有错误处理；逻辑通了，但有安全隐患；代码能跑，但性能很差。</p><p>在人类团队里，我们有&quot;代码审查&quot;（Code Review）这道关卡——写完代码，让另一个人看看。<strong><code>/code-review</code> 就是给 AI 也加上这道关卡。</strong></p><p>它像一个资深工程师坐到你旁边，帮你检查：</p><ul><li>&quot;这里 SQL 查询没用参数化，有注入风险&quot;</li><li>&quot;这段逻辑重复了三遍，可以抽成函数&quot;</li><li>&quot;这个错误处理太笼统了，用户不知道哪里出了问题&quot;</li></ul><p><strong>不只是找茬，还给改进建议。</strong></p><hr><h3 id="_4-learn-——-因为-这次学到的东西下次就忘了-很烦" tabindex="-1">4. <code>/learn</code> —— 因为&quot;这次学到的东西下次就忘了&quot;很烦 <a class="header-anchor" href="#_4-learn-——-因为-这次学到的东西下次就忘了-很烦" aria-label="Permalink to &quot;4. `/learn` —— 因为&quot;这次学到的东西下次就忘了&quot;很烦&quot;">​</a></h3><p>你在看项目代码，遇到一段用了 <code>useEffect</code> 的代码，不太理解依赖数组是干嘛的。你去 Google 了，看完了，懂了。三天后，又遇到了，又忘了。</p><p><strong><code>/learn</code> 的设计思路是：结合你自己的项目代码来教。</strong> 不是给你念文档，而是指着你项目里实际的代码告诉你&quot;看，这里就是这样用的&quot;。</p><p>用你自己的代码做教材，比看官方文档有效 10 倍——因为那是你正在处理的真实场景。</p><hr><h3 id="_5-verify-——-因为-改了一行代码不知道有没有搞坏别的" tabindex="-1">5. <code>/verify</code> —— 因为&quot;改了一行代码不知道有没有搞坏别的&quot; <a class="header-anchor" href="#_5-verify-——-因为-改了一行代码不知道有没有搞坏别的" aria-label="Permalink to &quot;5. `/verify` —— 因为&quot;改了一行代码不知道有没有搞坏别的&quot;&quot;">​</a></h3><p>你改了一行代码，心想：&quot;应该没问题吧……&quot;然后提交了。结果上线后发现，那个改动能影响到的功能全挂了。</p><p><strong><code>/verify</code> 就是提交前的全面检查：</strong> 构建能过吗？类型检查过吗？Lint 通过吗？测试全过吗？有遗留的 <code>console.log</code> 吗？</p><p>就像出门旅行前检查一遍：门锁了没？煤气关了没？灯关了没？<strong>一个命令，全面扫描，给你一个清晰的报告。</strong></p>',19)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-153",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20S1%5B%22%E8%83%BD%E6%9E%84%E5%BB%BA%E5%90%97%EF%BC%9F%22%5D%20--%3E%20S2%5B%22%E7%B1%BB%E5%9E%8B%E5%AF%B9%E5%90%97%EF%BC%9F%22%5D%0A%20%20%20%20S2%20--%3E%20S3%5B%22Lint%20%E8%BF%87%E5%90%97%EF%BC%9F%22%5D%0A%20%20%20%20S3%20--%3E%20S4%5B%22%E6%B5%8B%E8%AF%95%E5%85%A8%E8%BF%87%E5%90%97%EF%BC%9F%22%5D%0A%20%20%20%20S4%20--%3E%20S5%5B%22%E6%9C%89%E9%81%97%E7%95%99%E8%B0%83%E8%AF%95%E4%BB%A3%E7%A0%81%E5%90%97%EF%BC%9F%22%5D%0A%20%20%20%20S5%20--%3E%20REPORT%5B%22%F0%9F%93%8A%20%E6%8A%A5%E5%91%8A%EF%BC%9APASS%20%E2%9C%85%20%E6%88%96%20FAIL%20%E2%9D%8C%22%5D%0A%0A%20%20%20%20style%20S1%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20S2%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20S3%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20S4%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20S5%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20REPORT%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[3]||(a[3]=[t(" Loading... ",-1)])]),_:1})),a[10]||(a[10]=l(`<hr><h2 id="commands-vs-agents-为什么要分开" tabindex="-1">Commands vs Agents：为什么要分开？ <a class="header-anchor" href="#commands-vs-agents-为什么要分开" aria-label="Permalink to &quot;Commands vs Agents：为什么要分开？&quot;">​</a></h2><p>你可能会问：Commands 和 Agent（上一章讲的）有什么关系？为什么需要两套东西？</p><p><strong>一句话：Commands 是入口，Agent 是执行者。</strong></p><p>打个比方：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>餐厅的运作方式：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  你（顾客）→ 看菜单点菜（Command）→ 服务员接单 → 厨房做菜（Agent）</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  你不需要知道：</span></span>
<span class="line"><span>  - 厨房有几个厨师</span></span>
<span class="line"><span>  - 谁负责切菜谁负责炒菜</span></span>
<span class="line"><span>  - 用的是什么锅什么灶</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  你只需要：</span></span>
<span class="line"><span>  - 看菜单（Commands 列表）</span></span>
<span class="line"><span>  - 点菜（输入命令）</span></span>
<span class="line"><span>  - 等结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>这个分离的好处：</strong></p><ol><li><strong>简单</strong> — 你只需要记几个命令，不需要知道内部架构</li><li><strong>灵活</strong> — 同一个 <code>/plan</code> 命令，背后可能调用不同的 Agent 实现</li><li><strong>可扩展</strong> — 新增一个 Command 不需要改 Agent，反之亦然</li></ol>`,8)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-188",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20USER%5B%22%F0%9F%91%A4%20%E7%94%A8%E6%88%B7%22%5D%20--%3E%20CMD%5B%22%F0%9F%93%8B%20Commands%20%E5%B1%82%5Cn%2Fplan%20%2Ftdd%20%2Fverify%5Cn%E7%94%A8%E6%88%B7%E5%8F%AA%E9%9C%80%E8%A6%81%E8%AE%B0%E8%BF%99%E4%BA%9B%22%5D%0A%20%20%20%20CMD%20--%3E%20AGENT1%5B%22%F0%9F%A4%96%20Planner%20Agent%22%5D%0A%20%20%20%20CMD%20--%3E%20AGENT2%5B%22%F0%9F%A4%96%20TDD%20Agent%22%5D%0A%20%20%20%20CMD%20--%3E%20AGENT3%5B%22%F0%9F%A4%96%20Reviewer%20Agent%22%5D%0A%0A%20%20%20%20style%20USER%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20CMD%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20AGENT1%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20AGENT2%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20AGENT3%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[4]||(a[4]=[t(" Loading... ",-1)])]),_:1})),a[11]||(a[11]=l(`<hr><h2 id="commands-幕后-其实就是-markdown-文件" tabindex="-1">Commands 幕后：其实就是 Markdown 文件 <a class="header-anchor" href="#commands-幕后-其实就是-markdown-文件" aria-label="Permalink to &quot;Commands 幕后：其实就是 Markdown 文件&quot;">​</a></h2><p>你可能好奇，这些命令是怎么实现的？答案可能比你想象的简单——<strong>就是一堆 <code>.md</code> 文件。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commands/</span></span>
<span class="line"><span>├── plan.md           ← &quot;规划时你应该这样做：……&quot;</span></span>
<span class="line"><span>├── tdd.md            ← &quot;TDD 时你应该这样做：……&quot;</span></span>
<span class="line"><span>├── code-review.md    ← &quot;审查时你应该这样做：……&quot;</span></span>
<span class="line"><span>├── learn.md          ← &quot;教学时你应该这样做：……&quot;</span></span>
<span class="line"><span>└── verify.md         ← &quot;验证时你应该这样做：……&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>每个文件里用自然语言描述了这个命令该怎么执行。当你输入 <code>/plan</code> 时，系统找到 <code>plan.md</code>，把内容交给 AI，AI 就照着做。</p><p><strong>所以你完全可以自己写新的命令！</strong> 比如写一个 <code>/deploy</code>，让 AI 按你公司的部署流程来操作。</p><hr><h2 id="有-commands-和没有-commands-的对比" tabindex="-1">有 Commands 和没有 Commands 的对比 <a class="header-anchor" href="#有-commands-和没有-commands-的对比" aria-label="Permalink to &quot;有 Commands 和没有 Commands 的对比&quot;">​</a></h2>`,8)),(s(),e(r,null,{default:n(()=>[A(o,{id:"mermaid-207",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20NO%5B%22%E2%9D%8C%20%E6%B2%A1%E6%9C%89%20Commands%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20N1%5B%22%E4%BD%A0%22%5D%20--%3E%20N2%5B%22%E6%89%93%E4%B8%80%E5%A4%A7%E6%AE%B5%E8%AF%9D%E8%A7%A3%E9%87%8A%E5%B7%A5%E4%BD%9C%E6%96%B9%E5%BC%8F%22%5D%0A%20%20%20%20%20%20%20%20N2%20--%3E%20N3%5B%22AI%20%E7%8C%9C%E6%B5%8B%E4%BD%A0%E7%9A%84%E6%84%8F%E5%9B%BE%22%5D%0A%20%20%20%20%20%20%20%20N3%20--%3E%20N4%5B%22%E5%8F%AF%E8%83%BD%E7%90%86%E8%A7%A3%E5%81%8F%E4%BA%86%22%5D%0A%20%20%20%20%20%20%20%20N4%20--%3E%20N5%5B%22%E4%BD%A0%E5%86%8D%E7%BA%A0%E6%AD%A3%22%5D%0A%20%20%20%20%20%20%20%20N5%20--%3E%20N2%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20YES%5B%22%E2%9C%85%20%E6%9C%89%E4%BA%86%20Commands%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20Y1%5B%22%E4%BD%A0%22%5D%20--%3E%20Y2%5B%22%E8%BE%93%E5%85%A5%20%2Fplan%20%2B%20%E9%9C%80%E6%B1%82%22%5D%0A%20%20%20%20%20%20%20%20Y2%20--%3E%20Y3%5B%22AI%20%E6%8C%89%E9%A2%84%E8%AE%BE%E6%B5%81%E7%A8%8B%E5%B7%A5%E4%BD%9C%22%5D%0A%20%20%20%20%20%20%20%20Y3%20--%3E%20Y4%5B%22%E9%9D%A0%E8%B0%B1%E7%BB%93%E6%9E%9C%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20style%20NO%20fill%3A%23fce4ec%2Cstroke%3A%23f44336%0A%20%20%20%20style%20YES%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20N1%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20N2%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20N3%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20N4%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20N5%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20Y1%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20Y2%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20Y3%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20Y4%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...a[5]||(a[5]=[t(" Loading... ",-1)])]),_:1})),a[12]||(a[12]=l('<hr><h2 id="速查表-什么时候用什么" tabindex="-1">速查表：什么时候用什么？ <a class="header-anchor" href="#速查表-什么时候用什么" aria-label="Permalink to &quot;速查表：什么时候用什么？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你的情况</th><th>用这个命令</th><th>核心价值</th></tr></thead><tbody><tr><td>&quot;我要开始做一个新功能&quot;</td><td><code>/plan</code></td><td>先想后做，避免方向错误</td></tr><tr><td>&quot;我要写新代码&quot;</td><td><code>/tdd</code></td><td>先写测试，保证质量</td></tr><tr><td>&quot;我写完了想检查一下&quot;</td><td><code>/code-review</code></td><td>第二双眼睛找问题</td></tr><tr><td>&quot;我不懂这个技术概念&quot;</td><td><code>/learn</code></td><td>结合你的项目来教</td></tr><tr><td>&quot;我要提交代码了&quot;</td><td><code>/verify</code></td><td>全面检查，防止翻车</td></tr></tbody></table><p><strong>最常用的就 3 个：<code>/plan</code>、<code>/tdd</code>、/verify`。</strong> 其他的用到再查。</p><hr><h2 id="好处和代价" tabindex="-1">好处和代价 <a class="header-anchor" href="#好处和代价" aria-label="Permalink to &quot;好处和代价&quot;">​</a></h2><p><strong>好处：</strong></p><ul><li>🕐 省时间：10 轮对话 → 1 个命令</li><li>🎯 一致性：每次执行方式一样，不会跑偏</li><li>🧠 降低认知负担：不用记工作流程，记命令就行</li><li>🔧 可扩展：自己写 .md 文件就能新增命令</li></ul><p><strong>代价：</strong></p><ul><li>📝 需要花时间写好 Command 定义文件（不过默认的已经很好用）</li><li>🔄 命令太多反而记不住（建议只用核心的几个）</li><li>⚠️ 过于模板化可能限制创意性任务的灵活性</li></ul><hr><h2 id="对你自己的项目的启发" tabindex="-1">对你自己的项目的启发 <a class="header-anchor" href="#对你自己的项目的启发" aria-label="Permalink to &quot;对你自己的项目的启发&quot;">​</a></h2><ol><li><strong>识别重复沟通</strong> — 你跟 AI 有没有经常重复说的话？那就可以做成 Command</li><li><strong>工作流程固化</strong> — 最佳实践不该靠&quot;记住&quot;，应该靠&quot;自动化&quot;</li><li><strong>关注点分离</strong> — 用户不需要知道实现细节，只需要知道入口命令</li></ol><blockquote><p>💡 <strong>下一步</strong>：打开你的项目，试试输入 <code>/plan</code> + 你最近想做的一个功能，看看 AI 会输出什么样的实施计划。</p></blockquote>',14))])}const h=p(i,[["render",c]]);export{q as __pageData,h as default};
